export const toAmountConfigurationFormValues = (
  configuration: ActionPageAmountConfiguration
): ActionPageAmountConfigurationFormValues => {
  return {
    ...configuration,
    amountPresets: configuration?.amountPresets
      ? Object.keys(configuration?.amountPresets).reduce(
          (a, b) => {
            const presets = configuration.amountPresets![b as AmountPresetFrequency];

            if (presets) {
              return {
                ...a,
                [b]: presets.map((preset) => ({
                  ...preset,
                  amount: centsToDollars(preset.amount),
                })),
              };
            }

            return a;
          },
          {} as Record<AmountPresetFrequency, ActionPageAmountPreset[]>
        )
      : undefined,
    // have to ignore the timezone when parsing or else when viewing in other timezones it will shift the day
    futurePledgeDate: configuration.futurePledgeDate
      ? parseISO(configuration.futurePledgeDate.split('T')[0])
      : undefined,
    recurringMessage: configuration?.recurringMessage || '',
    transactionMaximum: centsToDollars(configuration?.transactionMaximum),
    transactionMinimum: centsToDollars(configuration?.transactionMinimum),
  };
};

const getDateInTimeZone = (date: Date, timeZone: string | undefined | null): string => {
  if (!timeZone) {
    return startOfDay(date).toISOString();
  }

  return zonedTimeToUtc(date, timeZone).toISOString();
};

export const toAmountConfigurationDetails = (
  configuration: ActionPageAmountConfigurationFormValues | undefined | null,
  account: Account | undefined
): ActionPageAmountConfiguration | undefined => {
  if (!configuration) {
    return undefined;
  }

  return {
    ...configuration,
    amountPresets: configuration?.amountPresets
      ? Object.keys(configuration?.amountPresets).reduce(
          (acc, nextPreset) => {
            const presets = configuration.amountPresets![nextPreset as AmountPresetFrequency];

            if (presets) {
              return {
                ...acc,
                [nextPreset]: presets.map((preset) => ({
                  ...preset,
                  amount: preset.amount ? currency(preset.amount).intValue : 0,
                })),
              };
            }

            return acc;
          },
          {} as Record<AmountPresetFrequency, ActionPageAmountPreset[]>
        )
      : undefined,
    futurePledgeDate: configuration.futurePledgeDate
      ? getDateInTimeZone(configuration.futurePledgeDate, account?.timeZone)
      : '',
    transactionMaximum: configuration?.transactionMaximum
      ? currency(configuration?.transactionMaximum).intValue
      : undefined,
    transactionMinimum: configuration?.transactionMinimum
      ? currency(configuration?.transactionMinimum).intValue
      : undefined,
  };
};

